import sqlite3
from pathlib import Path
from typing import Optional


class AccessDeniedError(Exception):
    pass


class FileNotFoundErrorInStore(Exception):
    pass


class FileAccessControlSystem:
    def __init__(self, db_path: str, base_directory: str):
        self.db_path = db_path
        self.base_directory = Path(base_directory).resolve()

    def _get_connection(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def initialize_schema(self) -> None:
        with self._get_connection() as conn:
            conn.executescript(
                """
                CREATE TABLE IF NOT EXISTS users (
                    id INTEGER PRIMARY KEY,
                    username TEXT NOT NULL UNIQUE,
                    access_level INTEGER NOT NULL
                );

                CREATE TABLE IF NOT EXISTS files (
                    id INTEGER PRIMARY KEY,
                    file_path TEXT NOT NULL UNIQUE,
                    required_access_level INTEGER NOT NULL
                );

                CREATE TABLE IF NOT EXISTS user_file_permissions (
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    can_read INTEGER NOT NULL DEFAULT 0,
                    PRIMARY KEY (user_id, file_id),
                    FOREIGN KEY (user_id) REFERENCES users(id),
                    FOREIGN KEY (file_id) REFERENCES files(id)
                );
                """
            )

    def add_user(self, username: str, access_level: int) -> int:
        with self._get_connection() as conn:
            cur = conn.execute(
                "INSERT INTO users (username, access_level) VALUES (?, ?)",
                (username, access_level),
            )
            return cur.lastrowid

    def add_file(self, file_path: str, required_access_level: int) -> int:
        with self._get_connection() as conn:
            cur = conn.execute(
                "INSERT INTO files (file_path, required_access_level) VALUES (?, ?)",
                (file_path, required_access_level),
            )
            return cur.lastrowid

    def set_user_file_permission(self, user_id: int, file_id: int, can_read: bool) -> None:
        with self._get_connection() as conn:
            conn.execute(
                """
                INSERT INTO user_file_permissions (user_id, file_id, can_read)
                VALUES (?, ?, ?)
                ON CONFLICT(user_id, file_id)
                DO UPDATE SET can_read = excluded.can_read
                """,
                (user_id, file_id, int(can_read)),
            )

    def _resolve_safe_path(self, relative_file_path: str) -> Path:
        candidate = (self.base_directory / relative_file_path).resolve()
        if self.base_directory not in candidate.parents and candidate != self.base_directory:
            raise AccessDeniedError("Invalid file path.")
        return candidate

    def has_read_permission(self, username: str, relative_file_path: str) -> bool:
        with self._get_connection() as conn:
            row = conn.execute(
                """
                SELECT
                    u.access_level AS user_access_level,
                    f.required_access_level AS file_required_access_level,
                    COALESCE(ufp.can_read, 0) AS can_read
                FROM users u
                JOIN files f ON f.file_path = ?
                LEFT JOIN user_file_permissions ufp
                    ON ufp.user_id = u.id AND ufp.file_id = f.id
                WHERE u.username = ?
                """,
                (relative_file_path, username),
            ).fetchone()

            if row is None:
                return False

            return bool(row["can_read"]) and row["user_access_level"] >= row["file_required_access_level"]

    def open_and_read_file(self, username: str, relative_file_path: str, encoding: Optional[str] = "utf-8") -> str:
        if not self.has_read_permission(username, relative_file_path):
            raise AccessDeniedError(f"User '{username}' does not have permission to read '{relative_file_path}'.")

        file_path = self._resolve_safe_path(relative_file_path)
        if not file_path.exists() or not file_path.is_file():
            raise FileNotFoundErrorInStore(f"File '{relative_file_path}' not found.")

        return file_path.read_text(encoding=encoding)


